UPDATE public.garden_import_queue SET payload = '{"species": "Yucca", "species_slug": "yucca", "varieties": [{"name": "Yucca elephantipes (Spineless Yucca, Giant Yucca)", "slug": "yucca-elephantipes-spineless-yucca-giant-yucca", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico and Guatemala, introduced to cultivation in 1800s", "traits": "Multi-trunked tree-like form, 3-9m height, thick elephant-foot base, soft-tipped sword-shaped leaves 60-120cm long, deep green color", "flesh_fruit": "", "yield_notes": "High productivity, fast-growing for a yucca, develops multiple branches over time", "growing_notes": "", "availability": "Widely available from Australian nurseries including Benara Nurseries, Australian Plants Online, and most Brisbane garden centers", "sort_order": 0}, {"name": "Yucca gigantea ''Variegata'' (Variegated Spineless Yucca)", "slug": "yucca-gigantea-variegata-variegated-spineless-yucca", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Cultivated selection from Y. gigantea, developed in horticultural trade", "traits": "Similar to species but with pale green leaves featuring broad cream-colored stripes along edges, 30-60cm leaves, 4-6m height potential", "flesh_fruit": "", "yield_notes": "Moderate growth, slightly slower than green form due to reduced chlorophyll", "growing_notes": "", "availability": "Available from specialty nurseries in Australia, North Carolina Extension program notes cultivar availability", "sort_order": 1}, {"name": "Yucca gigantea ''Marginata'' (Margined Spineless Yucca)", "slug": "yucca-gigantea-marginata-margined-spineless-yucca", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Horticultural selection", "traits": "Pale green leaves with narrow cream-colored stripe on both leaf edges, small teeth on margins, soft tips, multi-stemmed growth", "flesh_fruit": "", "yield_notes": "Moderate growth rate, forms attractive clumps", "growing_notes